@* Displays a single task with move-left/right buttons *@

<div class="task-card">
    <div class="task-header">
        <span class="task-title">@Task.Title</span>
        <span class="priority-badge priority-@Task.Priority.ToLowerInvariant()">@Task.Priority</span>
    </div>
    <div class="task-meta">
        <span class="task-assignee">@Task.Assignee</span>
        <span class="task-due">@Task.DueDate.ToString("MMM dd")</span>
    </div>
    <div class="task-actions">
        @if (ShowMoveLeft)
        {
            <button class="btn-move" @onclick="() => OnMoveLeft.InvokeAsync(Task)" disabled="@IsMoving">← Move Left</button>
        }
        @if (ShowMoveRight)
        {
            <button class="btn-move" @onclick="() => OnMoveRight.InvokeAsync(Task)" disabled="@IsMoving">Move Right →</button>
        }
    </div>
</div>

@code {
    [Parameter, EditorRequired] public TaskItem Task { get; set; } = default!;
    [Parameter] public bool ShowMoveLeft { get; set; }
    [Parameter] public bool ShowMoveRight { get; set; }
    [Parameter] public bool IsMoving { get; set; }
    [Parameter] public EventCallback<TaskItem> OnMoveLeft { get; set; }
    [Parameter] public EventCallback<TaskItem> OnMoveRight { get; set; }
}

@* Inline form for creating a new task within a column *@

<div class="add-task-form">
    <div class="form-field">
        <label>Title</label>
        <input type="text" @bind="title" @bind:event="oninput" placeholder="Task title" />
    </div>
    <div class="form-field">
        <label>Assignee</label>
        <input type="text" @bind="assignee" @bind:event="oninput" placeholder="Assignee name" />
    </div>
    <div class="form-field">
        <label>Priority</label>
        <select @bind="priority">
            <option value="High">High</option>
            <option value="Medium">Medium</option>
            <option value="Low">Low</option>
        </select>
    </div>
    <div class="form-field">
        <label>Due Date</label>
        <input type="date" @bind="dueDate" />
    </div>
    <div class="form-actions">
        <button class="btn-save" @onclick="HandleSave" disabled="@(isSaving || string.IsNullOrWhiteSpace(title))">
            @(isSaving ? "Saving..." : "Save")
        </button>
        <button class="btn-cancel" @onclick="HandleCancel" disabled="@isSaving">Cancel</button>
    </div>
    @if (errorMessage is not null)
    {
        <p class="form-error">@errorMessage</p>
    }
</div>

@code {
    [Parameter, EditorRequired] public string Status { get; set; } = "";
    [Parameter] public EventCallback<TaskItem> OnTaskCreated { get; set; }
    [Parameter] public EventCallback OnCancel { get; set; }

    private string title = "";
    private string assignee = "";
    private string priority = "Medium";
    private DateTime dueDate = DateTime.Today.AddDays(7);
    private bool isSaving;
    private string? errorMessage;

    [Inject] private ITaskService TaskService { get; set; } = default!;

    private async Task HandleSave()
    {
        isSaving = true;
        errorMessage = null;
        try
        {
            var created = await TaskService.CreateTaskAsync(title.Trim(), assignee.Trim(), priority, dueDate);
            await OnTaskCreated.InvokeAsync(created);
        }
        catch (Exception ex)
        {
            errorMessage = $"Failed to create task: {ex.Message}";
        }
        finally
        {
            isSaving = false;
        }
    }

    private async Task HandleCancel()
    {
        await OnCancel.InvokeAsync();
    }
}

@* Search bar for filtering tasks by title *@

<div class="search-bar">
    <input type="text"
           placeholder="Search tasks by title..."
           value="@SearchText"
           @oninput="HandleInput" />
</div>

@code {
    [Parameter] public string SearchText { get; set; } = "";
    [Parameter] public EventCallback<string> OnSearchChanged { get; set; }

    private async Task HandleInput(ChangeEventArgs e)
    {
        await OnSearchChanged.InvokeAsync(e.Value?.ToString() ?? "");
    }
}

